import jsonimport refrom pathlib import Pathfrom typing import List, Dict, Any, Tuplefrom sklearn.feature_extraction.text import TfidfVectorizerfrom sklearn.metrics.pairwise import cosine_similarityCHUNKS_PATH = Path("data/chunks.json")DEFAULT_TOP_K = 3MIN_SCORE_THRESHOLD = 0.03def expand_query(query: str) -> str:    """    Expand common patient wording into terms more likely to appear    in the scraped procedure pages.    """    q = query.lower().strip()    expansions = []    if any(word in q for word in ["cost", "price", "fee", "fees", "charge", "charges", "expensive"]):        expansions.extend([            "cost fees price charges rebates medicare account faqs"        ])    if any(word in q for word in ["prepare", "preparation", "ready", "before", "fasting", "drink water"]):        expansions.extend([            "prepare preparation before examination fast full bladder instructions"        ])    if any(word in q for word in ["risk", "safe", "danger", "harm", "side effect", "after effects"]):        expansions.extend([            "risks safe after effects harmful"        ])    if any(word in q for word in ["results", "report"]):        expansions.extend([            "results report doctor"        ])    if any(word in q for word in ["how long", "duration", "take", "minutes"]):        expansions.extend([            "how long take duration minutes"        ])        if "abdominal" in q:        expansions.extend([            "abdomen ultrasound abdomen prepare preparation fasting six hours"        ])    if "abdomen" in q:        expansions.extend([            "abdominal ultrasound abdomen fasting six hours prepare"        ])    expanded_query = q    if expansions:        expanded_query = q + " " + " ".join(expansions)    expanded_query = re.sub(r"\s+", " ", expanded_query).strip()    return expanded_queryclass Retriever:    def __init__(self, chunks: List[Dict[str, Any]]):        if not chunks:            raise ValueError("No chunks provided to Retriever.")        self.chunks = chunks        self.texts = [chunk["text"] for chunk in chunks]        self.vectorizer = TfidfVectorizer(            lowercase=True,            stop_words="english",            ngram_range=(1, 3),        )        self.matrix = self.vectorizer.fit_transform(self.texts)    def retrieve(self, query: str, top_k: int = DEFAULT_TOP_K) -> List[Dict[str, Any]]:        """        Return the top-k most relevant chunks for a query.        """        if not query or not query.strip():            raise ValueError("Query must not be empty.")        query = query.strip()        expanded_query = expand_query(query)        query_vector = self.vectorizer.transform([expanded_query])        scores = cosine_similarity(query_vector, self.matrix).flatten()        ranked_indices = scores.argsort()[::-1]        results = []        for idx in ranked_indices[:top_k]:            score = float(scores[idx])            if score < MIN_SCORE_THRESHOLD:                continue            chunk = self.chunks[idx]            results.append({                "chunk_id": chunk["chunk_id"],                "title": chunk["title"],                "url": chunk["url"],                "text": chunk["text"],                "score": round(score, 4),                "word_count": chunk.get("word_count"),            })                    seen_texts = set()        deduped_results = []                for idx in ranked_indices:            score = float(scores[idx])                    if score < MIN_SCORE_THRESHOLD:                continue                    chunk = self.chunks[idx]            text_key = chunk["text"].strip().lower()                    if text_key in seen_texts:                continue                    seen_texts.add(text_key)                    deduped_results.append({                "chunk_id": chunk["chunk_id"],                "title": chunk["title"],                "url": chunk["url"],                "text": chunk["text"],                "score": round(score, 4),                "word_count": chunk.get("word_count"),            })                    if len(deduped_results) >= top_k:                break                return deduped_resultsdef load_chunks(file_path: Path) -> List[Dict[str, Any]]:    if not file_path.exists():        raise FileNotFoundError(f"Chunks file not found: {file_path}")    with file_path.open("r", encoding="utf-8") as f:        chunks = json.load(f)    if not isinstance(chunks, list):        raise ValueError("Expected chunks.json to contain a list of chunk records.")    if not chunks:        raise ValueError("chunks.json is empty.")    required_keys = {"chunk_id", "title", "url", "text"}    for i, chunk in enumerate(chunks):        missing = required_keys - set(chunk.keys())        if missing:            raise ValueError(f"Chunk at index {i} is missing required keys: {missing}")    return chunksdef build_retriever(chunks_path: Path = CHUNKS_PATH) -> Retriever:    chunks = load_chunks(chunks_path)    return Retriever(chunks)def format_results(results: List[Dict[str, Any]]) -> str:    if not results:        return "No relevant content found."    lines = []    for i, result in enumerate(results, start=1):        lines.append(            f"[{i}] {result['title']} | score={result['score']} | {result['url']}\n"            f"Chunk ID: {result['chunk_id']}\n"            f"Chunk Text:\n{result['text']}\n"        )    return "\n".join(lines)def main() -> None:    try:        retriever = build_retriever()    except Exception as e:        print(f"Failed to build retriever: {e}")        return    print("Retriever ready. Type a question, or 'exit' to quit.")    while True:        query = input("\nQuestion: ").strip()        if query.lower() in {"exit", "quit"}:            print("Goodbye.")            break        try:            results = retriever.retrieve(query)            print("\nTop matches:")            print(format_results(results))        except ValueError as e:            print(f"Input error: {e}")        except Exception as e:            print(f"Retrieval error: {e}")if __name__ == "__main__":    main()